package main

import (
    "context"
    "fmt"
    "time"
)

func main() {
    // ---- Cancellation ----
    fmt.Println("=== Cancellation ===")

    ctx, cancel := context.WithCancel(context.Background())

    go func() {
        for {
            select {
            case <-ctx.Done():
                fmt.Println("Worker stopped")
                return
            default:
                fmt.Println("Working...")
                time.Sleep(100 * time.Millisecond)
            }
        }
    }()

    time.Sleep(250 * time.Millisecond)
    cancel()
    time.Sleep(100 * time.Millisecond)

    // ---- Timeout ----
    fmt.Println("\n=== Timeout ===")

    ctxTimeout, cancelTimeout := context.WithTimeout(context.Background(), 200*time.Millisecond)
    defer cancelTimeout()

    go func() {
        for {
            select {
            case <-ctxTimeout.Done():
                fmt.Println("Timeout worker stopped")
                return
            default:
                fmt.Println("Timeout worker working...")
                time.Sleep(50 * time.Millisecond)
            }
        }
    }()

    time.Sleep(300 * time.Millisecond)

    // ---- Deadline ----
    fmt.Println("\n=== Deadline ===")

    deadline := time.Now().Add(150 * time.Millisecond)
    ctxDeadline, cancelDeadline := context.WithDeadline(context.Background(), deadline)
    defer cancelDeadline()

    go func() {
        for {
            select {
            case <-ctxDeadline.Done():
                fmt.Println("Deadline worker stopped")
                return
            default:
                fmt.Println("Deadline worker working...")
                time.Sleep(50 * time.Millisecond)
            }
        }
    }()

    time.Sleep(200 * time.Millisecond)

    // ---- Cancellation propagation ----
    fmt.Println("\n=== Cancellation Propagation ===")

    parentCtx, parentCancel := context.WithCancel(context.Background())
    childCtx, childCancel := context.WithCancel(parentCtx)

    go func() {
        select {
        case <-childCtx.Done():
            fmt.Println("Child stopped")
        }
    }()

    parentCancel()
    time.Sleep(50 * time.Millisecond)
    childCancel()  // Already cancelled by parent
}

