    "fmt"
    "time"
)

func main() {
    // Forgetting to check Done in goroutine
    ctx, cancel := context.WithCancel(context.Background())

    go func() {
        // Never checks ctx.Done()
        for {
            fmt.Println("Never stops")
            time.Sleep(100 * time.Millisecond)
        }
    }()

    time.Sleep(250 * time.Millisecond)
    cancel()  // Does nothing
    time.Sleep(100 * time.Millisecond)
}

phase2.explanation:
The goroutine doesn't check `ctx.Done()`, so cancellation has no effect.

**The fix:**
```go
go func() {
    for {
        select {
        case <-ctx.Done():
            return
        default:
            fmt.Println("Stops when cancelled")
            time.Sleep(100 * time.Millisecond)
        }
    }
}()
```

**Go-chan says:**
"Check `ctx.Done()` to respond to cancellation."

