package main

import (
    "context"
    "fmt"
    "time"
)

func main() {
    ctx, cancel := context.WithTimeout(context.Background(), 200*time.Millisecond)
    defer cancel()

    go func() {
        for {
            select {
            case <-ctx.Done():
                fmt.Println("Timeout:", ctx.Err())
                return
            default:
                fmt.Println("Working...")
                time.Sleep(50 * time.Millisecond)
            }
        }
    }()

    time.Sleep(300 * time.Millisecond)
    fmt.Println("Done")
}
